class Trie {
    val root = TrieNode()

    fun insert(word: String) {
        var node = root
        for (c in word) {
            val idx = c - 'a'
            if (node.children[idx] == null) node.children[idx] = TrieNode()
            node = node.children[idx]!!
        }
        node.isEndOfWord = true
    }

    fun search(word: String): Boolean = findNode(word)?.isEndOfWord == true
    fun startsWith(prefix: String): Boolean = findNode(prefix) != null

    private fun findNode(str: String): TrieNode? {
        var node = root
        for (c in str) {
            node = node.children[c - 'a'] ?: return null
        }
        return node
    }
}

