data class Edge(val to: Int, val weight: Int)

fun dijkstra(graph: List<List<Edge>>, source: Int): IntArray {
    val dist = IntArray(graph.size) { Int.MAX_VALUE }
    val pq = PriorityQueue<Pair<Int, Int>>(compareBy { it.first })
    dist[source] = 0; pq.add(0 to source)
    while (pq.isNotEmpty()) {
        val (d, u) = pq.poll()
        if (d > dist[u]) continue
        for (e in graph[u]) {
            val nd = d + e.weight
            if (nd < dist[e.to]) { dist[e.to] = nd; pq.add(nd to e.to) }
        }
    }
    return dist
}

fun topologicalSort(graph: Map<Int, List<Int>>): List<Int> {
    val inDegree = mutableMapOf<Int, Int>()
    graph.keys.forEach { inDegree[it] = 0 }
    graph.forEach { (_, n) -> n.forEach { inDegree[it] = inDegree.getOrDefault(it, 0) + 1 } }
    val queue = ArrayDeque<Int>()
    inDegree.filter { it.value == 0 }.keys.forEach { queue.addLast(it) }
    val result = mutableListOf<Int>()
    while (queue.isNotEmpty()) {
        val u = queue.removeFirst(); result.add(u)
        graph[u]?.forEach { v -> inDegree[v] = inDegree[v]!! - 1; if (inDegree[v] == 0) queue.addLast(v) }
    }
    return result
}

